#include <iostream>
#include <limits>
#nclude <string>

class Calculator {
public:
    int add(int a, int b) const { return a + b; }
    double add(double a, double b) const { return a + b; }
    int add(int a, int b, int c) const { return a + b + c; }
};

int main() {
    Calculator calc;
    std::cout << calc.add(5, 3) << std::endl;
    std::cout << calc.add(-10, 7) << std::endl;
    std::cout << calc.add(0, 0) << std::endl;
    std::cout << calc.add(std::numeric_limits<int>::max(), 0) << std::endl;
    std::cout << calc.add(std::numeric_limits<int>::min(), 0) << std::endl;
    std::cout << calc.add(5.5, 3.2) << std::endl;
    std::cout << calc.add(-10.1, 7.5) << std::endl;
    std::cout << calc.add(0.0, 0.0) << std::endl;
    std::cout << calc.add(123456789.123, 987654321.987) << std::endl;
    std::cout << calc.add(0.0000001, 0.0000002) << std::endl;
    std::cout << calc.add(1, 2, 3) << std::endl;
    std::cout << calc.add(-1, -2, -3) << std::endl;
    std::cout << calc.add(10, -5, 2) << std::endl;
    std::cout << calc.add(100, 200, 300) << std::endl;
    std::cout << calc.add(std::numeric_limits<int>::max() - 2, 1, 1) << std::endl;
    return 0;
}
